<template>
    <div class="base_report_right_msg">
        <Row class="base_report_right_top">
        <RadioGroup v-model="clickMsg" type="button" @on-change="selectTop">
            <Radio label="查询" :style="{borderRadius:'5px',border:'1px solid #eee'}">查询</Radio>
            <Radio label="维护表信息" :style="{margin:'0 10px',borderRadius:'5px',border:'1px solid #eee'}">维护表信息</Radio>
            <Radio label="血缘关系" :style="{borderRadius:'5px',border:'1px solid #eee'}">血缘关系</Radio>
        </RadioGroup>
        </Row>
        <Row :style="{marginTop:'30px'}">
            <div v-if="clickMsg=='查询'">
                <selectMsg />
            </div>
            <div v-if="clickMsg=='维护表信息'">
                <replaceReport />
            </div>
            <div v-if="clickMsg=='血缘关系'">
                <bloodIndex />
            </div>
        </Row>
    </div>
</template>
<script>
import selectMsg from "@/components/DataManager/reportMsg/selectMsg"
import replaceReport from "@/components/DataManager/reportMsg/replaceReport"
import bloodIndex from "@/components/DataManager/bloodLineage/bloodIndex"
export default {
    data(){
        return{
            clickMsg:"",
        }
    },
    computed:{
        ids(){
            return this.$store.state.listIds
        }
    },
    created(){
        console.log(this.ids)
    },
    components:{
        selectMsg,
        replaceReport,
        bloodIndex
    },
    mounted(){
        var base_report_right_msg = document.querySelector('.base_report_right_msg')
        base_report_right_msg.style.minHeight=window.innerHeight+'px'
    },
    methods:{
        // 头部三个按键
        selectTop(el){
            if (el ==="查询"){
                console.log(this.ids.id)
                this.dgtablefield(this.ids.id,function(el){
                    console.log(el)
                })
            }else if(el ==="维护表信息"){

            }else if(el ==="血缘关系"){

            }
        }
    },
    watch:{
        ids(){
            this.clickMsg=""
        }
    }
}
</script>
<style scoped>
.base_report_right_top{
   border-bottom: 1px solid #eee; 
}
.ivu-radio-wrapper:before{
    border:0px solid red !important;
    width:0px !important;
}
</style>





