</template>
<script>
import FlowNorm from "@/components/Standards/useNorm/FlowNorm"
import NameNorm from "@/components/Standards/useNorm/NameNorm"
import dispatchMonit from "@/components/quayControl/dispatchMonit/dispatchMonit"

export default {
    data () {
        return {
            isCollapsed: ""
        }
    },
    components:{
        FlowNorm,
        NameNorm,
        dispatchMonit
    },
    mounted(){
        var stan_base = document.querySelector('.stan_base')
        stan_base.style.minHeight=window.innerHeight+'px'
    },
    methods:{
        updat(el){
            console.log(el)
        }
    }
}
</script>
<style scoped>
.stanbase_top{
   border-bottom: 1px solid #eee; 
   margin-bottom: 20px;
}

</style>





