// mutations:转变,变化,  类似于methods 存放事件 
// mutations可以处理异步操作,而methods一般来说处理同步操作
export default{
	// 触发此函数的方法
		// store.commit("方法名","传递的参数")  
			// this.$store.commit("reduce",el)
		// 这边接受时 mutation("此state","形参")
	mutation(state,el){
		this.state.count+=el
	},
	//---------------------元数据管理 -->表信息&&血缘关系
	// 左边下拉选择
	listIds(state,el){
		var counts = state.listIds.counts+1
		state.listIds={
			id:el,
			counts:counts
		}
	}
	
}


