// import axios from '@/libs/api.request'
import '@/api'
const Plugin1 = {
	// 调用vue.use(plugin1)之后,他会自动回调这个onstall函数并传递vue对象过来
    // 局部调用方法: this.positionCity(function(el){console.log(el)})
    // 具体调用方法.请看本目录下的haveAway文件
    install(Vue, b, c) {
        // 例子1:get
        // 定位city       //--需要值类型 : 1
        // 接口:https://elm.cangdu.org/v1/cities?type=guess
        Vue.prototype.positionCity = function(success){
            let api="/v1/cities?type=guess";
            // promise写法
            var _this=this
            this.axios.get(api,{
                params:{
                }
            }).then(function(response){
                success&&success(response.data)
            })
        },
        // 例子2:post
        // 获取登录信息  //需要用户名:user_name 和密码:password
        // 接口:https://elm.cangdu.org/admin/login
        Vue.prototype.postway=function(el,bl,success){
            let api = "/admin/login"
            var _this=this
            this.axios.get(api,{
                user_name:el,
                password :bl
            }).then(function(response){
                success&&success(response.data)
            })
        }
        // 测试
        Vue.prototype.textMsg=function(success){
            let api = "/dgdatasourcemap/info/1"
            var _this=this
            this.axios.get(api).then(function(response){
                success&&success(response.data)
            })
        }
        // -------------------------元数据页面

        // ------------表信息&血缘关系
        // 获取表层级选择
        Vue.prototype.dgtablelevel=function(success){
            let api = "/dgtablelevel/list"
            var _this=this
            this.axios.get(api,{
                params:{
                    page:1,
                    limit:999,
                    sidx:"",
                    order:"ASC"
                }
            }).then(function(response){
                success&&success(response.data)
            })
        }
        // 根据根据表层即选择的获取的id  获取库名和表名
        Vue.prototype.dgtablefield=function(el,success){
            let api = "dgtablefield/list"
            var _this=this
            this.axios.get(api,{
                params:{
                    page:1,
                    limit:999,
                    sidx:"",
                    order:"ASC",
                    filter:el
                }
            }).then(function(response){
                success&&success(response.data)
            })
        }


        // -------指标库
        
        // 元数据管理 / 指标库类型
        Vue.prototype.dgindicatorstype=function(success){
            let api = "dgindicatorstype/list"
            var _this=this
            this.axios.get(api,{
                params:{
                    page:1,
                    limit:999,
                    sidx:"",
                    order:"ASC"
                }
            }).then(function(response){
                success&&success(response.data.page.list)
            })
        }
        // 元数据管理 / 指标库业态
        Vue.prototype.dgindicatorsbusiness=function(success){
            let api = "/dgindicatorsbusiness/list"
            var _this=this
            this.axios.get(api,{
                params:{
                    page:1,
                    limit:999,
                    sidx:"",
                    order:"ASC"
                }
            }).then(function(response){
                success&&success(response.data.page.list)
            })
        }
        //  元数据管理 / 指标库专题
        Vue.prototype.dgindicatorssubject=function(success){
            let api = "/dgindicatorssubject/list"
            var _this=this
            this.axios.get(api,{
                params:{
                    page:1,
                    limit:999,
                    sidx:"",
                    order:"ASC"
                }
            }).then(function(response){
                success&&success(response.data.page.list)
            })
        }
        // 元数据管理 / 指标库查询 核心数据
        Vue.prototype.dgindicatorscore=function(el,success){
            let api = "/dgindicatorscore/list"
            var _this=this
            this.axios.get(api,{
                params:{
                    page:el.page,
                    limit:50,
                    sidx:"",
                    order:"ASC",
                    filter:el.filter,
                }
            }).then(function(response){
                success&&success(response.data)
            }).catch(function(response){
                success&&success(response.data)
            })
        }
        // 核心数据删除 el为数组  id的数组
        Vue.prototype.dgindicatorscoreDelete=function(el,success){
            let api = "/dgindicatorscore/delete"
            var _this=this
            this.axios.get(api,{
                params:{
                    ids:el,
                }
            }).then(function(response){
                success&&success(response.data)
            })
        }
        // 核心数据保存
        Vue.prototype.dgindicatorscoreSave=function(el,success){
            let api = "/dgindicatorscore/save"
            var _this=this
            this.axios.post(api,{el}).then(function(response){
                success&&success(response.data)
            })
        }
    },
};
// 获取当前时间
function CurentTime()
    { 
        var now = new Date();
       
        var year = now.getFullYear();       //年
        var month = now.getMonth() + 1;     //月
        var day = now.getDate();            //日
       
        var hh = now.getHours();            //时
        var mm = now.getMinutes();          //分
        var ss = now.getSeconds();          //分
        var clock = year + "-";
       
        if(month < 10)clock += "0";
       
        clock += month + "-";
       
        if(day < 10) clock += "0";
           
        clock += day + " ";
       
        if(hh < 10)clock += "0";
           
        clock += hh + ":";
        if (mm < 10) clock += '0'; 
        clock += mm + ":"; 
        if (ss < 10 )clock+="0";
        clock += ss;
        return(clock); 
    } 
export { Plugin1};




