// The Vue build version to load with the `import` command
// (runtime-only or standalone) has been set in webpack.base.conf with an alias.
import Vue from 'vue'
import App from './App'
import router from './router'
import axios from 'axios'
import VueAxios from 'vue-axios'
import store from './store'
// 引入ivew样式
import iView from 'iview';
import 'iview/dist/styles/iview.css';
Vue.use(iView);

import "@/static/css/reset.css"
// 引入easy-table
import 'vue-easytable/libs/themes-base/index.css'
import {VTable,VPagination} from 'vue-easytable'
Vue.component(VTable.name, VTable)
Vue.component(VPagination.name, VPagination)

import {Plugin1} from './lib/require'
// 从参数2开始,给install方法添加参数
Vue.use(Plugin1,"mmp","omg","shit")
Vue.use(VueAxios, axios)

import mavonEditor from 'mavon-editor'
// markdown-it对象：md.s_markdown, md => mavonEditor实例
//                 or
//                 mavonEditor.markdownIt 
import 'mavon-editor/dist/css/index.css'
// use
Vue.use(mavonEditor)

// 自定义列组件
Vue.component('table-operation',{
  template:`<span>
    <a href="" :style="{height:'100%'}" @click.stop.prevent="update(rowData,index)">保存&nbsp;/&nbsp;</a>
    <a href="" :style="{height:'100%'}" @click.stop.prevent="deleteRow(rowData,index)">删除</a>
  </span>`,
  props:{
      rowData:{
          type:Object
      },
      field:{
          type:String
      },
      index:{
          type:Number
      }
  },
  methods:{
      update(){
         // 参数根据业务场景随意构造
         let params = {type:'edit',index:this.index,rowData:this.rowData};
         this.$emit('on-custom-comp',params);
      },
      deleteRow(){
          // 参数根据业务场景随意构造
          let params = {type:'delete',index:this.index,ids:this.rowData.id};
          this.$emit('on-custom-comp',params);
      }
  }
})
/* eslint-disable no-new */
new Vue({
  el: '#app',
  router,
  components: { App },
  template: '<App/>',
  store
})



