<template>
    <div class="base_report_left_msg">
        <Row>
            表层级选择
        </Row>
        <Row>
            <Select v-model="surface" style="width:90%">
                <Option v-for="item in surfaces" :value="item.id" :key="item.id">{{item.remark}}</Option>
            </Select>
        </Row>
        <br>
        <Row>
            库名
        </Row>
        <Row>
            <Select v-model="libraryName" style="width:90%" filterable>
                <Option v-for="item in libraryNames" :value="item.id" :key="item.id">{{item.remark}}</Option>
            </Select>
        </Row>
        <br>
        <Row>
            表名
        </Row>
        <Row>
            <Select v-model="ReportName" style="width:90%" filterable>
                <Option v-for="item in ReportNames" :value="item.id" :key="item.id">{{item.remark}}</Option>
            </Select>
        </Row>
    </div>
</template>
<script>
export default {
    data () {
        return {
            surface: '',
            surfaces: [{remark:'xx1',id:1},{remark:"xx2",id:2}],
            // 业务选择
            libraryName:"",
            libraryNames:[{remark:'xx1',id:1},{remark:"xx2",id:2}],
            // 专题选择
            ReportName:"",
            ReportNames:[{remark:'xx1',id:1},{remark:"xx2",id:2}],
        }
    },
    components:{
    },
    created(){
        this.dgtablelevel(function(el){

        })
    },
    watch:{
        surface(){
            var ids = this.ReportName?this.ReportName:0
            this.$store.commit("listIds",ids)
        },
        libraryName(){
            var ids = this.ReportName?this.ReportName:0
            this.$store.commit("listIds",ids)
        },
        ReportName(){
            var ids = this.ReportName?this.ReportName:0
            this.$store.commit("listIds",ids)
        }
    }
}
</script>




