<template>
    <div class="layout">
        <Layout>
            <Header class="bloder">
                <Menu mode="horizontal" theme="dark" active-name="1" class="bloder">
                    <div class="layout-logo">
                        永辉云创 · 数据化治理平台
                    </div>
                    <div class="layout-nav">
                        <MenuItem name="1">
                            <Icon type="ios-navigate"></Icon>
                             name
                        </MenuItem>
                    </div>
                </Menu>
            </Header>
            <Layout class="aa">
                <Sider ref="side1" hide-trigger collapsible :collapsed-width="78" v-model="isCollapsed">
                <Menu active-name="1-1" theme="dark" width="auto" :class="menuitemClasses" @on-select="routerLink">
                    <MenuItem name="1-1">
                        <Icon type="ios-navigate"></Icon>
                        <span>元数据管理</span>
                    </MenuItem>
                    <MenuItem name="1-2">
                        <Icon type="ios-search"></Icon>
                        <span>质量监控管理</span>
                    </MenuItem>
                    <MenuItem name="1-3">
                        <Icon type="ios-settings"></Icon>
                        <span>接口文档管理</span>
                    </MenuItem>
                    <MenuItem name="1-4">
                        <Icon type="ios-settings"></Icon>
                        <span>标准规范管理</span>
                    </MenuItem>
                </Menu>
            </Sider>
            <Layout>
                <Header :style="{padding: 0,height:'50px',lineHeight:'50px'}" class="layout-header-bar">
                    <Icon @click.native="collapsedSider" :class="rotateIcon" :style="{margin: '0 20px'}" type="md-menu" size="24"></Icon>
                    <Breadcrumb :style="{display:'inline-block'}">
                        <BreadcrumbItem>{{inlineClick}}</BreadcrumbItem>
                    </Breadcrumb>
                </Header>
                <Content :style="{ borderTop:'1px solid #eee',background: '#fff', minHeight: '600px',minWidth: '800px',padding:'18px 15px 0'}">
                    <keep-alive>
                        <router-view></router-view>
                    </keep-alive>
                </Content>
            </Layout>
            </Layout>
        </Layout>
    </div>
</template>
<script>
    export default {
        data () {
            return {
                isCollapsed: false,
                inlineClick:"元数据管理"
            }
        },
        created(){
        },
        components:{
        },
        computed: {
            rotateIcon () {
                return [
                    'menu-icon',
                    this.isCollapsed ? 'rotate-icon' : ''
                ];
            },
            menuitemClasses () {
                return [
                    'menu-item',
                    this.isCollapsed ? 'collapsed-menu' : ''
                ]
            }
        },
        methods: {
            collapsedSider () {
                this.$refs.side1.toggleCollapse();
            },
            routerLink(el){
                if(el == '1-1'){
                    this.$router.push({name:'DataManagerBaseIndex'})
                    this.inlineClick = "元数据管理"
                }
                if(el == '1-2'){
                    this.$router.push({name:'baseControl'})
                    this.inlineClick = "质量监控管理"
                }
                if(el == '1-3'){
                    this.$router.push({name:'basePort'})
                    this.inlineClick = "接口文档管理"
                }
                if(el == '1-4'){
                    this.$router.push({name:'StanBase'})
                    this.inlineClick = "标准规范管理"
                }
            }
        }
    }
</script>
<style scoped>
.layout-logo{
    width: 230px;
    height: 60px;
    line-height: 60px;
    color:#fff;
    font-size: 18px;
    border-radius: 3px;
    font-weight: 700;
    float: left;
    position: relative;
    top: 0px;
    left: 20px;
}
.layout-nav{
    width: 100px;
    margin: 0 auto;
    margin-right: 20px;
}
.layout{
    border: 1px solid #d7dde4;
    background: #f5f7f9;
    position: relative;
    border-radius: 4px;
    overflow: hidden;
}
.bloder{
    background-color: rgb(0,0,0) !important;
}
.layout-header-bar{
    background: #fff;
    box-shadow: 0 1px 1px rgba(0,0,0,.1);
}
.layout-logo-left{
    width: 90%;
    height: 30px;
    border-radius: 3px;
    margin: 15px auto;
}
.menu-icon{
    transition: all .3s;
}
.rotate-icon{
    transform: rotate(-90deg);
}
.menu-item span{
    display: inline-block;
    overflow: hidden;
    width: 100px;
    text-overflow: ellipsis;
    white-space: nowrap;
    vertical-align: bottom;
    color:#fff;
    font-weight: 700;
    transition: width .2s ease .2s;
}
.menu-item i{
    transform: translateX(0px);
    transition: font-size .2s ease, transform .2s ease;
    vertical-align: middle;
    font-size: 18px;
}
.collapsed-menu span{
    width: 0px;
    transition: width .2s ease;
}
.collapsed-menu i{
    transform: translateX(5px);
    transition: font-size .2s ease .2s, transform .2s ease .2s;
    vertical-align: middle;
    font-size: 22px;
}
</style>


