<template>
<div class="selectmsg">
    <div class='replace-right-button'>
        <Row>
            <Button type="primary" @click="updat('维护表')">维护表</Button>
        </Row>
        <Row :style="{marginTop:'20px'}">
            <Button type="primary" @click="updat('新增表')">新增表</Button>
        </Row>
    </div>
    <div v-if="cleckMsg=='维护表'">
        <Row>
            <reportBaseMsg />
        </Row>
        <Row>
        <reportBaseInfo />
        </Row>
        <Row>
            <reportBaseClassify />
        </Row>
        <Row>
            <dispatchMessage />
        </Row>
        <Row :style="{marginTop:'15px'}" >
            <Col span="24" :style="{textAlign:'center'}">
                <Button type="primary">提交</Button>
            </Col>
        </Row>
    </div>
    <div v-if="cleckMsg=='新增表'">
        <AddReportMsg />
    </div>
</div>
</template>
<script>
    import reportBaseMsg from "@/components/DataManager/replaceSmallMsg/rereportBaseMsg"
    import reportBaseInfo from "@/components/DataManager/replaceSmallMsg/rereportBaseInfo"
    import reportBaseClassify from "@/components/DataManager/replaceSmallMsg/rereportBaseClassify"
    import dispatchMessage from "@/components/DataManager/replaceSmallMsg/redispatchMessage"
    import AddReportMsg from "@/components/DataManager/replaceSmallMsg/AddReportMsg"

    export default {
        data(){
            return{
                cleckMsg:"维护表"
            }
        },
        components:{
            reportBaseMsg,
            reportBaseInfo,
            reportBaseClassify,
            dispatchMessage,
            AddReportMsg
        },
        methods:{
            updat(el){
                this.cleckMsg = el
            }
        }
    }
</script>
<style scoped>
    .selectmsg{
        min-width: 800px;
        height:100%;
        overflow: hidden;
        overflow-y: scroll;
        padding-bottom: 30px;
        position: relative;

    }
    .selectmsg::-webkit-scrollbar {display:none}
    .replace-right-button{
        position: absolute;
        right:30px;
        top:30px;
        z-index: 10;
    }
</style>



