<template>
    <div>
        <Row :style="{marginTop:'0px',lineHeight:'30px'}">
            <Col span="3">表层级选择 :</Col>
            <Col span="6">
                <Select v-model="surface" style="width:100%">
                    <Option v-for="item in surfaces" :value="item.value" :key="item.value">{{item.label}}</Option>
                </Select>
            </Col>
        </Row>
        <Row :style="{marginTop:'10px',lineHeight:'30px'}">
            <Col span="3">库&emsp;&emsp;&emsp;名 :</Col>
            <Col span="6">
                <Select v-model="surface" style="width:100%">
                    <Option v-for="item in surfaces" :value="item.value" :key="item.value">{{item.label}}</Option>
                </Select>
            </Col>
        </Row>
        <Row :style="{marginTop:'10px',lineHeight:'30px'}">
            <Col span="3">表&emsp;&emsp;&emsp;名 :</Col>
            <Col span="6">
                <Input  v-model="ReportName" placeholder="请输入新表名"/>
            </Col>
            <Col span="3" :style="{color:'red',marginLeft:'12px'}" v-if="checkedReportName">重复表名!!</Col>
        </Row>
        <Row :style="{marginTop:'10px',lineHeight:'30px'}">
            <Col span="3">执行脚本(选):</Col>
            <Col span="15">
                <Input v-model="executeInsert" type="textarea" :rows="10" placeholder="请输入执行脚本" />
            </Col>
        </Row>
        <Row :style="{marginTop:'30px',lineHeight:'30px'}">
            <Col span="8" :style="{textAlign:'center'}">
                <Button type="primary">新&emsp;增</Button>
            </Col>
        </Row>
    </div>
</template>
<script>
export default {
    data(){
        return{
            // 表层级选择
            surface: '',
            surfaces: [
                {
                    value: 'New York',
                    label: 'New York'
                },
                {
                    value: 'London',
                    label: 'London'
                },
                {
                    value: 'Sydney',
                    label: 'Sydney'
                },
                {
                    value: 'Ottawa',
                    label: 'Ottawa'
                },
                {
                    value: 'Paris',
                    label: 'Paris'
                },
                {
                    value: 'Canberra',
                    label: 'Canberra'
                }
            ],
            // 库名
            libraryName:"",
            libraryNames:[],
            // 表名
            ReportName:"",
            ReportNames:[],
            // 检查表明是否重复
            checkedReportName:false,
            // 执行脚本
            executeInsert:""
        }
    },
    methods:{

    },
    watch:{
        ReportName(news){
            console.log(news)
            var that = this
            var counts = 0
            
            // this.ReportNames.map(val=>{
            this.surfaces.map(val=>{
                if(val.value==news){
                    counts+=1
                }
            })
            if(counts){
                that.checkedReportName = true
            }else{
                that.checkedReportName = false
            }

        }
    }
}
</script>




