<template>
    <div class="Order_index">
        <Row :style="{lineHeight:'30px'}">
            <Col span="2" :style="{paddingLeft:'5px'}">
                指标类型
            </Col>
            <Col span="4">
            <Select v-model="surface" style="width:90%">
                <Option v-for="item in surfaces" :value="item.id" :key="item.id">{{item.remark}}</Option>
            </Select>
            </Col>
            <Col span="2" :style="{paddingLeft:'5px'}">
                业务选择
            </Col>
            <Col span="4">
            <Select v-model="libraryName" style="width:90%">
                <Option v-for="item in libraryNames" :value="item.id" :key="item.id">{{item.remark}}</Option>
            </Select>
            </Col>
            <Col span="2" :style="{paddingLeft:'5px'}">
                专题选择
            </Col>
            <Col span="4">
            <Select v-model="ReportName" style="width:90%">
                <Option v-for="item in ReportNames" :value="item.id" :key="item.id">{{item.remark}}</Option>
            </Select>
            </Col>
            <Col span="2" offset="1">
             <Button type="primary" :style="{width:'100%'}" @click="selectMsg">查询</Button>
            </Col>
        </Row>
        <Row :style="{marginTop:'20px'}">
            <Col span="21">
                <v-table
                    is-horizontal-resize
                    column-width-drag
                    :height="600"
                    style="width:100%"
                    :columns="columns"
                    :table-data="tableData"
                    row-hover-color="#eee"
                    row-click-color="#edf7ff"
                    :cell-edit-done="cellEditDone"
                    @on-custom-comp="customCompFunc"
                ></v-table>
            </Col>
        </Row>
        <Row :style="{lineHeight:'30px'}">
            <Col span="2" :style="{textAlign:'center',fontSize:'25px'}">
                <Icon type="ios-add" class="orderIndex_add_icon" @click="addIcon"/>
            </Col>
        </Row>
    </div>
</template>
<script>
export default {
    data(){
        return{
            // 指标类型
            surface: '',
            surfaces: [],
            // 业务选择
            libraryName:"",
            libraryNames:[],
            // 专题选择
            ReportName:"",
            ReportNames:[],
            // 自定义表格
            tableData: [
                {"name":"赵伟","field_name":"字段名称","field_description":"字段描述","scence_description":"场景描述","analyst":"分析师","sql_logic":"sql逻辑","create_time":"更新时间",'id':"1"},
            ],
            columns: [
                {field: 'name', title: '业态', width: 100, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'field_name', title: '字段名称', width: 100, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'field_description', title: '字段描述', width: 150, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'scence_description', title: '场景描述', width: 150, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'analyst', title: '分析师', width: 100, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'sql_logic', title: 'sql逻辑', width: 100, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'create_time', title: '更新时间', width: 100, titleAlign: 'center', columnAlign: 'center',isResize:true},
                {field: 'custome-adv', title: '操作',width: 100, titleAlign: 'center',columnAlign:'center',componentName:'table-operation',isResize:true}
            ],
            // 核心部分所有信息,以id为准
            dataMsg:[],
            // 页码选择
            pages:1
        }
    },
    created(){
        var that = this
        // 元数据管理 / 指标库类型
        this.dgindicatorstype(function(el){
            el.map(val=>{
                if(val.remark!==""){
                    that.surfaces.push(val)
                }
            })
        })
       // 元数据管理 / 指标库业态
        this.dgindicatorsbusiness(function(el){
            el.map(val=>{
                if(val.remark!==""){
                    that.libraryNames.push(val)
                }
            })
        })
        //  元数据管理 / 指标库专题
        this.dgindicatorssubject(function(el){
            el.map(val=>{
                if(val.remark!==""){
                    that.ReportNames.push(val)
                }
            })
        })
    },
    methods:{
        // 点击查询 查询内容
        selectMsg(){
            var that = this
            var ids = [this.surface?this.surface:0,this.libraryName?this.libraryName:0,this.ReportName?this.ReportName:0]
            var pusrse = {
                filter:ids,
                page:this.pages
            }
            this.dgindicatorscore(pusrse,function(el){
                that.dataMsg=[]
                that.tableData=[]
                if(el.code==1){
                     // 目标数据  el.page.list
                    el.page.list.map(val=>{
                         var tableData = {"name":val.name,"field_name":val.field_name,"field_description":val.field_description,"scence_description":val.scence_description,"analyst":val.analyst,"sql_logic":val.sql_logic,"create_time":val.create_time,'id':val.id}
                         
                         for(var item in tableData){
                             if(tableData[item]){

                             }else{
                                 tableData[item]="-"
                             }
                         }
                         that.tableData.push(tableData)
                         that.dataMsg.push(val)
                    })
                }else{
                    this.$Message.info(el.message)
                }
            })
        },
        // 单元格按键点击
        customCompFunc(params){
            if (params.type === 'delete'){  //删除
                var ids =[params.ids]
                if(params.ids){
                    this.$delete(this.dataMsg,params.index);
                    this.$delete(this.tableData,params.index);
                    // this.dgindicatorscoreDelete(ids,function(el){
                    //     alert(el)
                        //   需要把删除的信息获取到新的id 赋值给当前的人
                    // })
                }else{
                    this.$Message.info('当前为新增字段,无法删除,请尽快完善')
                }
            }else if(params.type === 'edit'){ // 保存
                // 更新数据源
                this.dataMsg.map(val=>{
                    if(val.id==params.rowData.id){
                        for(var item in val){
                            if(params.rowData[item]){
                                val[item]== params.rowData[item]
                            }
                        }
                    }
                })
                var readyMsg =this.dataMsg.filter(val=>val.id==params.rowData.id)[0]
                console.log(readyMsg)
                this.dgindicatorscoreSave(readyMsg,function(el){
                    console.log(el)
                })
            }
        },
        // 单元格编辑回调
        cellEditDone(newValue,oldValue,rowIndex,rowData,field){
            this.tableData[rowIndex][field] = newValue;
        },
        // 单元格添加
        addIcon(){
            var searchCounts=0
            this.dataMsg.map(val=>{
                if(val.id==0){
                    console.log(val.id)
                    searchCounts+=1
                }
            })
            if(searchCounts==0){
                var addMsg = {"name":"-","field_name":"-","field_description":"-","scence_description":"-","analyst":"-","sql_logic":"-","create_time":this.CurentTime(),'id':0}
                this.tableData =[...this.tableData,addMsg]
                this.dataMsg.push(this.dataModel())
            }else{
                this.$Message.info('你当前有一条新增的信息,请处理后添加');
            }
        },
        CurentTime(){
            var now = new Date();
            var year = now.getFullYear();       //年
            var month = now.getMonth() + 1;     //月
            var day = now.getDate();            //日
            var hh = now.getHours();            //时
            var mm = now.getMinutes();          //分
            var ss = now.getSeconds();          //分
            var clock = year + "-";
            if(month < 10)clock += "0";
            clock += month + "-";
            if(day < 10) clock += "0";
            clock += day + " ";
            if(hh < 10)clock += "0";
            clock += hh + ":";
            if (mm < 10) clock += '0'; 
            clock += mm + ":"; 
            if (ss < 10 )clock+="0";
            clock += ss;
            return(clock); 
        },
        // 数据源模板
        dataModel(){
            return {
                "analyst": "",
                "businessid": 0,
                "creater": 0,
                "creatername": "",
                "createtime":this.CurentTime(),
                "disabled": 0,
                "fielddescription": "",
                "fieldname": "",
                "id": 0,
                "indicatorid": 0,
                "modifier": 0,
                "modifiername": "",
                "modifytime":this.CurentTime(),
                "projectid": 0,
                "remark": "",
                "scencedescription": "",
                "sqllogic": "",
                "typeofbusiness": "",
                "version": 0    
            }
        }

    }
}
</script>
<style scoped>
    .Order_index{
        padding-left: 20px;
        position: relative;
    }
    .orderIndex_add_icon{
        cursor: pointer;
    }
    .v-table-row{
        height:40px !important;
    }
</style>




