<template>
    <div class="rereportbaseinfo">
        <Row :style="{color:'black',fontSize:'14px',fontWeight:'700',marginTop:'30px'}">
            二.表字段描述
        </Row>
        <Row :style="{marginTop:'20px'}">
            <Col span="21" offset="1">
                <v-table
                    is-horizontal-resize
                    column-width-drag
                    :height="600"
                    style="width:100%"
                    :columns="columns"
                    :table-data="tableData"
                    row-hover-color="#eee"
                    row-click-color="#edf7ff"

                    :cell-edit-done="cellEditDone"
                    @on-custom-comp="customCompFunc"
                ></v-table>
            </Col>
        </Row>
        <Row :style="{lineHeight:'30px'}">
            <Col span="2" offset="1" :style="{textAlign:'center',fontSize:'25px'}">
                <Icon type="ios-add" class="orderIndex_add_icon" @click="addIcon"/>
            </Col>
        </Row>
    </div>
</template>
<script>
export default {
    data(){
        return{
            tableData: [
                {"name":"赵伟","tel":"156*****1987","hobby":"钢琴、书法、唱歌","address":"金陵东路569号17楼"},
                {"name":"李伟","tel":"182*****1538","hobby":"钢琴、书法、唱歌","address":"南桥镇立新路12号2楼"},
                {"name":"孙伟","tel":"161*****0097","hobby":"钢琴、书法、唱歌","address":"城桥镇八一路739号"},
                {"name":"周伟","tel":"197*****1123","hobby":"钢琴、书法、唱歌","address":"青浦镇章浜路24号"},
                {"name":"吴伟","tel":"183*****6678","hobby":"钢琴、书法、唱歌","address":"乐都西路867-871号"}
            ],
            columns: [
                {field: 'name', title: '表名', width: 100, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'tel', title: '字段名', width: 100, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'hobby', title: '字段类型', width: 150, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'address', title: '字段备注', width: 150, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'address', title: '存储类型', width: 150, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'address', title: '区分字段', width: 150, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'address', title: '分区描述', width: 150, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'address', title: '负责分析师', width: 150, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'address', title: '开发优化', width: 150, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true},
                {field: 'custome-adv', title: '操作',width: 50, titleAlign: 'center',columnAlign:'center',componentName:'table-operation',isResize:true}
            ]
        }
    },
    components:{
        
    },
    methods:{
        // 单元格按键点击
        customCompFunc(params){
            console.log(params);
            if (params.type === 'delete'){  //删除
                this.$delete(this.tableData,params.index);
            }
        },
        // 单元格编辑回调
        cellEditDone(newValue,oldValue,rowIndex,rowData,field){
            console.log(newValue)
            this.tableData[rowIndex][field] = newValue;
        },
        // 单元格添加
        addIcon(){
            var addMsg = {"tel":this.CurentTime(),"name": '.',"hobby":".","address":"."}
            this.tableData.push(addMsg)
        },
        // 获取时间
        CurentTime(){ 
            var now = new Date();
            var year = now.getFullYear();       //年
            var month = now.getMonth() + 1;     //月
            var day = now.getDate();            //日
            var hh = now.getHours();            //时
            var mm = now.getMinutes();          //分
            var ss = now.getSeconds();          //分
            var clock = year + "-";
            if(month < 10)clock += "0";
            clock += month + "-";
            if(day < 10) clock += "0";
            clock += day + " ";
            if(hh < 10)clock += "0";
            clock += hh + ":";
            if (mm < 10) clock += '0'; 
            clock += mm + ":"; 
            if (ss < 10 )clock+="0";
            clock += ss;
            return(clock); 
        } 
    }

}
</script>
<style scoped>
    .rereportbaseinfo{
        width:100%;
    }
</style>





