import Vue from 'vue'
import Router from 'vue-router'
import Home from '@/components/Home/home'

Vue.use(Router)
import DataManagerBaseIndex from "@/components/DataManager/baseInfo/index"
import StanBase from "@/components/Standards/baseInfos/StanBase"
import baseControl from "@/components/quayControl/baseControl/baseControl"
import basePort from "@/components/portDocument/basePortInfo/basePort"

export default new Router({
  routes: [
    {
      path: '/',
      name: 'Tom',
      component: Home
    },
    {
      path: '/Home',
      name: 'Home',
      component: Home,
      children:[
        {
          path: '/Home/DataManagerBaseIndex',
          name: 'DataManagerBaseIndex',
          component: DataManagerBaseIndex
        },{
          path: '/Home/StanBase',
          name: 'StanBase',
          component: StanBase
        },{
          path: '/Home/baseControl',
          name: 'baseControl',
          component: baseControl
        },{
          path: '/Home/basePort',
          name: 'basePort',
          component: basePort
        },
      ]
    }
  ]
})



